import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a personal loan?", a: "A personal loan is a fixed-term loan often used for debt consolidation, home projects, medical bills, or large purchases." },
  { q: "How do you qualify for a personal loan?", a: "Lenders usually review credit score, income, debt-to-income ratio, employment, and repayment history." },
  { q: "What is a good interest rate for a personal loan?", a: "A good rate depends on credit profile and market conditions. Borrowers with excellent credit typically qualify for lower rates." },
  { q: "What is the difference between secured and unsecured loans?", a: "Secured loans use collateral. Unsecured loans do not, so they may have higher rates because the lender has more risk." },
  { q: "Should you use a personal loan to pay off credit card debt?", a: "It can help if the loan rate is lower and you avoid adding new card debt, but fees and repayment discipline matter." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function payment(principal: number, apr: number, months: number) { const r = apr / 100 / 12; return r === 0 ? principal / months : principal * r / (1 - Math.pow(1 + r, -months)); }
function schedule(principal: number, apr: number, months: number) {
  const monthly = payment(principal, apr, months); let balance = principal; const rows = [];
  for (let month = 1; month <= months && month <= 120; month++) { const interest = balance * apr / 100 / 12; const principalPaid = Math.min(balance, monthly - interest); balance = Math.max(0, balance - principalPaid); rows.push({ month, payment: monthly, principal: principalPaid, interest, balance }); }
  return rows;
}

export default function PersonalLoanCalculator() {
  useCurrencyVersion();
  const [amount, setAmount] = useState(10000);
  const [rate, setRate] = useState(12);
  const [term, setTerm] = useState(36);
  const result = useMemo(() => { const monthly = payment(amount, rate, term); return { monthly, totalInterest: monthly * term - amount, total: monthly * term, schedule: schedule(amount, rate, term) }; }, [amount, rate, term]);
  const rates = [6, 9, 12, 15, 18, 24];
  return (
    <>
      <SEOHead title="Free Personal Loan Calculator Online - Calculate Personal Loan Payments Instantly | CalcHive" description="Free online personal loan calculator. Calculate monthly personal loan payments, total interest and full amortization schedule for any loan amount and rate instantly. 100% free, no signup required." canonical="/personal-loan-calculator" keywords="free personal loan calculator, personal loan payment calculator free online, calculate personal loan interest free, personal loan monthly payment calculator free, unsecured loan calculator free" category="Financial Calculators" breadcrumbName="Free Personal Loan Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Personal Loan Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate monthly personal loan payments, total interest, total paid, and amortization.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Loan amount</label><input type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Annual rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Term months</label><input type="number" value={term} onChange={(e) => setTerm(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{money(result.totalInterest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total paid</p><p className="text-lg font-extrabold text-foreground">{money(result.total)}</p></div></div>
          <div className="overflow-x-auto mt-5"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Amortization Schedule</caption><thead className="bg-muted/60"><tr>{["Month", "Payment", "Principal", "Interest", "Balance"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.schedule.map((row) => <tr key={row.month}><td className="py-2.5 px-3">{row.month}</td><td className="py-2.5 px-3">{money(row.payment)}</td><td className="py-2.5 px-3">{money(row.principal)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Personal Loan Payments for Free</h2><p className="text-muted-foreground leading-relaxed">Use the amortized loan formula with loan amount, APR, and term to estimate the fixed monthly payment.</p><h2 className="text-2xl font-bold text-foreground">How Credit Score Affects Personal Loan Interest Rates</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Personal Loan Monthly Payment by Rate and Term</caption><thead className="bg-muted/60"><tr>{["Interest Rate", "12 Months", "24 Months", "36 Months", "48 Months", "60 Months on $10,000"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rates.map((r) => <tr key={r}><td className="py-2.5 px-3 font-semibold">{r}%</td>{[12, 24, 36, 48, 60].map((m) => <td key={m} className="py-2.5 px-3">{money(payment(10000, r, m))}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Personal Loan Payment Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Compare repayment terms and interest rates before borrowing so you understand the full cost.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/personal-loan-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


